from itertools import permutations

class Solution(object):
    def minimumMoves(self, grid):
        # Find cells with excess stones (sources) and empty cells (targets)
        sources = []  # (r, c) with excess stones
        targets = []  # (r, c) with 0 stones

        for r in range(3):
            for c in range(3):
                if grid[r][c] > 1:
                    sources.extend([(r, c)] * (grid[r][c] - 1))
                elif grid[r][c] == 0:
                    targets.append((r, c))

        # sources and targets have equal length
        # Try all permutations of sources matched to targets
        min_moves = float('inf')
        for perm in permutations(range(len(sources))):
            moves = sum(
                abs(sources[perm[i]][0] - targets[i][0]) + abs(sources[perm[i]][1] - targets[i][1])
                for i in range(len(targets))
            )
            min_moves = min(min_moves, moves)

        return min_moves
